--- 获取图鉴信息
function LxHeroBookHandler:OnHeroBookInfoResp(pb)
    ModuleCenter.HeroBook:SetHeroBookInfos(pb.heroBooks)
end

--- 图鉴升级/激活
function LxHeroBookHandler:OnHeroBookLevelUpResp(pb)
    ModuleCenter.HeroBook:SetHeroBookInfo(pb.heroBook)
    FireEvent(EventNames.REFRESH_HERO_ALLRP,{
        refreshWay = LxProtoIds.HeroBookLevelUpResp,
    })
    FireEvent(EventNames.HERO_INFO_CHANGE)
end

