function LxHeroBookHandler:OnHeroLikeInfoResp(pb)
end

--- 对英雄点赞
function LxHeroBookHandler:OnHeroLikeOperateResp(pb)
    local type = pb.type
    if type == 0 then
        --- 点亮喜欢
        ShowSysMsg(I18nText(7920))
    elseif type == 1 then
        --- 取消点亮
        ShowSysMsg(I18nText(7921))
    end
end

--- 对英雄评论
function LxHeroBookHandler:OnHeroCommentResp(pb)
end

--- 对评论点赞
function LxHeroBookHandler:OnHeroCommentLikeResp(pb)
    local type = pb.type
    local msg = type == 1 and I18nText(7927) or I18nText(7926)
    ShowSysMsg(msg)
end

--- 热门阵容列表
function LxHeroBookHandler:OnHeroHotTroopListResp(pb)
    ModuleCenter.HeroBook:SetHotTroopObjs(pb)
end

--- 热门阵容点赞
function LxHeroBookHandler:OnHotTroopLikeResp(pb)
    ModuleCenter.HeroBook:SetHotTroopObjLove(pb)
end

